  { name: 'React Component', filename: 'Component.tsx', language: 'typescript', code: 'import React, { useState, useEffect } from "react";

interface Props {
  title: string;
  initialCount?: number;
}

export function Component({ title, initialCount = 0 }: Props) {
  const [count, setCount] = useState(initialCount);
  const [items, setItems] = useState<string[]>([]);

  useEffect(() => {
    console.log(`Count changed to ${count}`);
  }, [count]);

  const addItem = () => {
    setItems(prev => [...prev, `Item ${prev.length + 1}`]);
  };

  return (
    <div style={{ padding: "2rem", fontFamily: "system-ui" }}>
      <h1>{title}</h1>
      <p>Count: {count}</p>
      <div style={{ display: "flex", gap: "8px", margin: "1rem 0" }}>
        <button onClick={() => setCount(c => c - 1)}>-</button>
        <button onClick={() => setCount(c => c + 1)}>+</button>
        <button onClick={addItem}>Add Item</button>
      </div>
      <ul>
        {items.map((item, i) => (
          <li key={i}>{item}</li>
        ))}
      </ul>
    </div>
  );
}' },
