  { name: 'Express Server', filename: 'server.js', language: 'javascript', code: 'const express = require("express");
const app = express();
const PORT = 3000;

app.use(express.json());
app.use((req, res, next) => {
  console.log(`${req.method} ${req.url}`);
  next();
});

let items = [
  { id: 1, name: "Item 1", done: false },
  { id: 2, name: "Item 2", done: true },
];

app.get("/", (req, res) => res.json({ message: "API running!", version: "1.0" }));
app.get("/api/items", (req, res) => res.json({ items, total: items.length }));
app.get("/api/items/:id", (req, res) => {
  const item = items.find(i => i.id === parseInt(req.params.id));
  item ? res.json(item) : res.status(404).json({ error: "Not found" });
});
app.post("/api/items", (req, res) => {
  const item = { id: items.length + 1, name: req.body.name, done: false };
  items.push(item);
  res.status(201).json(item);
});
app.delete("/api/items/:id", (req, res) => {
  items = items.filter(i => i.id !== parseInt(req.params.id));
  res.json({ message: "Deleted" });
});

app.listen(PORT, () => console.log(`Server: http://localhost:${PORT}`));' },
