  { name: 'Python Flask API', filename: 'app.py', language: 'python', code: 'from flask import Flask, jsonify, request
from functools import wraps

app = Flask(__name__)

items = [
    {"id": 1, "name": "Item 1", "price": 9.99},
    {"id": 2, "name": "Item 2", "price": 19.99},
]

def validate_json(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        if not request.is_json:
            return jsonify({"error": "Content-Type must be application/json"}), 400
        return f(*args, **kwargs)
    return decorated

@app.route("/")
def index():
    return jsonify({"message": "Flask API running!", "version": "1.0"})

@app.route("/api/items")
def get_items():
    return jsonify({"items": items, "total": len(items)})

@app.route("/api/items/<int:item_id>")
def get_item(item_id):
    item = next((i for i in items if i["id"] == item_id), None)
    if not item:
        return jsonify({"error": "Not found"}), 404
    return jsonify(item)

@app.route("/api/items", methods=["POST"])
@validate_json
def add_item():
    data = request.get_json()
    new_item = {"id": len(items) + 1, "name": data["name"], "price": data.get("price", 0)}
    items.append(new_item)
    return jsonify(new_item), 201

@app.route("/api/items/<int:item_id>", methods=["DELETE"])
def delete_item(item_id):
    global items
    items = [i for i in items if i["id"] != item_id]
    return jsonify({"message": "Deleted"})

if __name__ == "__main__":
    app.run(debug=True, port=5000)' },
